mapper.select:
SELECT payment_method as paymentMethod, COUNT(*) as count FROM consumption_record WHERE consumption_time BETWEEN #{startTime} AND #{endTime} AND status = 'completed' AND payment_method IS NOT NULL
AND store_id = #{storeId}
GROUP BY payment_method ORDER BY count DESC

SELECT HOUR(consumption_time) as hour, COUNT(*) as count, COALESCE(SUM(total_amount), 0) as amount FROM consumption_record WHERE consumption_time BETWEEN #{startTime} AND #{endTime} AND status = 'completed'
AND store_id = #{storeId}
GROUP BY HOUR(consumption_time) ORDER BY hour

SELECT cr.id, cr.consumption_no as consumptionNo, cr.total_amount as amount, cr.consumption_time as createTime, cr.payment_method as paymentMethod, m.name as memberName, m.phone as memberPhone, s.store_name as storeName FROM consumption_record cr LEFT JOIN member m ON cr.member_id = m.id LEFT JOIN store s ON cr.store_id = s.id WHERE cr.status = 'completed'
AND cr.store_id = #{storeId}
ORDER BY cr.consumption_time DESC LIMIT #{limit}

SELECT COUNT(*)
FROM consumption_record
WHERE consumption_time BETWEEN #{startTime} AND #{endTime}
AND status = 'completed'

    AND store_id = #{storeId}

SELECT COALESCE(SUM(total_amount), 0)
FROM consumption_record
WHERE consumption_time BETWEEN #{startTime} AND #{endTime}
AND status = 'completed'

    AND store_id = #{storeId}

SELECT COUNT(DISTINCT member_id)
FROM consumption_record
WHERE consumption_time BETWEEN #{startTime} AND #{endTime}
AND status = 'completed'
AND member_id IS NOT NULL

    AND store_id = #{storeId}

SELECT cr.*
FROM consumption_record cr
LEFT JOIN member m ON cr.member_id = m.id


        AND m.member_no LIKE CONCAT('%', #{memberNo}, '%')


        AND m.name LIKE CONCAT('%', #{memberName}, '%')


        AND cr.consumption_no LIKE CONCAT('%', #{consumptionNo}, '%')


        AND cr.payment_method = #{paymentMethod}


        AND cr.consumption_time >= #{startDate}


        AND cr.consumption_time <= #{endDate}


ORDER BY cr.consumption_time DESC

SELECT DATE_FORMAT(consumption_time, '%Y-%m') as month, COUNT(*) as orderCount, COALESCE(SUM(total_amount), 0) as revenue FROM consumption_record WHERE status = 'completed'
AND consumption_time >= #{startTime}
AND consumption_time <= #{endTime}
GROUP BY DATE_FORMAT(consumption_time, '%Y-%m') ORDER BY month ASC

SELECT DATE_FORMAT(created_time, '%Y-%m') as month, COUNT(*) as newMembers FROM member
AND created_time >= #{startTime}
AND created_time <= #{endTime}
GROUP BY DATE_FORMAT(created_time, '%Y-%m') ORDER BY month ASC
